<template>
  <div class="onboarding-container">
    <div class="header">
      <div class="logo">
        <img src="/favicon.ico" alt="Pomelo" class="logo-img">
        <span class="logo-text">西柚 Pomelo</span>
      </div>
      <h2>Merchant Onboarding</h2>
      <p>Complete the form to join our platform</p>
    </div>
    
    <ProgressBar currentStep="4" />
    
    <div class="form-section">
      <h3>Account</h3>
      <p class="section-desc">Login settings</p>
      
      <el-form ref="form" :model="form" :rules="rules" label-width="180px">
        <el-row>
          <el-col :span="12">
            <el-form-item label="Login Username*" prop="userName">
              <el-input v-model="form.userName" placeholder="Your username" maxlength="30"/>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="Login Password*" prop="password">
              <el-input v-model="form.password" placeholder="Create a secure password" type="password" maxlength="20" show-password/>
            </el-form-item>
          </el-col>
        </el-row>
        
        <h4>BANKING INFORMATION</h4>
        
        <el-row>
          <el-col :span="12">
            <el-form-item label="Bank Name" prop="accountName">
              <el-input v-model="form.accountName" placeholder="Bank of America" maxlength="50"/>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="Routing Number*" prop="rn">
              <el-input v-model="form.rn" placeholder="9 digits" maxlength="25"/>
            </el-form-item>
          </el-col>
        </el-row>
        
        <el-form-item label="Account Number*" prop="bankAccount">
          <el-input v-model="form.bankAccount" placeholder="Account number" maxlength="25"/>
        </el-form-item>
        
        <el-form-item label="Account Holder Name*" prop="acHolderName">
          <el-input v-model="form.acHolderName" placeholder="Name on bank account" maxlength="50"/>
        </el-form-item>
        
        <h4>REQUIRED DOCUMENTS</h4>
        
        <el-row>
          <el-col :span="12">
            <el-form-item label="Business Registration Document" prop="businessLicense">
              <div class="upload-box">
                <BigFileUpload 
                  @handleUploadSuccess="handleUploadSuccess"
                  :defaultUrl = "form.businessLicense"
                  :imgWidth="180"
                  :imgHeight="138"
                  :flag="3"
                  :isOnlyShow="false"
                />
              </div>
            </el-form-item>
          </el-col>
          <el-col :span="12">
            <el-form-item label="Permit License" prop="permitLicense">
              <div class="upload-box">
                <BigFileUpload 
                  @handleUploadSuccess="handleUploadSuccess"
                  :defaultUrl = "form.permitLicense"
                  :imgWidth="180"
                  :imgHeight="138"
                  :flag="4"
                  :isOnlyShow="false"
                />
              </div>
            </el-form-item>
          </el-col>
        </el-row>
        
        <el-form-item class="form-buttons">
          <el-button class="save-draft-btn" @click="saveDraft">Save Draft</el-button>
          <div class="action-buttons">
            <el-button class="back-btn" @click="prevStep">{{leftStr}} Back</el-button>
            <el-button class="next-btn" @click="submitForm">Next ></el-button>
          </div>
        </el-form-item>
      </el-form>
    </div>
    
    <div class="footer-note">
      <p>Your information is secure and will only be used for merchant verification.</p>
    </div>
  </div>
</template>

<script>
/* eslint-disable vue/multi-word-component-names */
import BigFileUpload from '@/components/BigFileUpload.vue'

export default {
  name: 'Account',
  components: {
    BigFileUpload,
    ProgressBar: () => import('@/components/ProgressBar.vue')
  },
  data() {
    return {
      leftStr: "<",
      form: {
        userName: '',
        password: '',
        accountName: '',
        bankAccount: '',
        rn: '',
        acHolderName: '',
        businessLicense: '',
        permitLicense: ''
      },
      rules: {
        userName: [
          { required: true, message: "Please input login username", trigger: "blur" },
          { min: 2, max: 20, message: 'Login username length must be between 2 and 20', trigger: 'blur' }
        ],
        password: [
          { required: true, message: "Password cannot be empty", trigger: "blur" },
          { min: 5, max: 20, message: 'Password length must be between 5 and 20', trigger: 'blur' },
          { pattern: /^[^<>'"|\\]+$/, message: "Cannot contain illegal characters: < > \" ' \\ |", trigger: "blur" }
        ],
        accountName: [
          { required: true, message: "Please input bank name", trigger: "blur" }
        ],
        bankAccount: [
          { required: true, message: "Please input account number", trigger: "blur" }
        ],
        rn: [
          { required: true, message: "Please input routing number", trigger: "blur" }
        ],
        acHolderName: [
          { required: true, message: "Please input account holder name", trigger: "blur" }
        ],
        businessLicense: [
          { required: true, message: "Please upload business registration document", trigger: "blur" }
        ],
        permitLicense: [
          { required: true, message: "Please upload permit license", trigger: "blur" }
        ]
      }
    }
  },
  methods: {
    saveDraft() {
      this.$message.success('Draft saved successfully!');
    },
    prevStep() {
      this.$router.push('/contact');
    },
    submitForm() {
      this.$refs["form"].validate((valid) => {
        if (valid) {
          // 保存当前表单数据到sessionStorage
          sessionStorage.setItem('accountInfo', JSON.stringify(this.form));
          
          // 收集所有表单数据
          const allFormData = {
            ...JSON.parse(sessionStorage.getItem('businessInfo') || '{}'),
            ...JSON.parse(sessionStorage.getItem('serviceInfo') || '{}'),
            ...JSON.parse(sessionStorage.getItem('contactInfo') || '{}'),
            ...this.form
          };
          
          // 调用API接口
          this.$axios.post(process.env.VUE_APP_API_BASE_URL + '/app/merchant/addMerchant', allFormData)
            .then(response => {
              if (response.data.code === 200) {
                this.$message.success('Merchant added successfully!');
                // 跳转到成功页面
                this.$router.push('/success');
              } else {
                this.$message.error('Failed to add merchant: ' + response.data.message);
              }
            })
            .catch(error => {
              console.error('API call failed:', error);
              this.$message.error('Network error, please try again later');
            });
        }
      });
    },
    handleUploadSuccess(response, flag) {
      // 处理文件上传成功的回调
      console.log('File uploaded successfully:', response, flag);
      switch(flag) {
        case 3:
          this.form.businessLicense = response.url || response.path || response;
          break;
        case 4:
          this.form.permitLicense = response.url || response.path || response;
          break;
      }
    }
  },
  mounted() {
    // 从sessionStorage加载数据
    const savedData = sessionStorage.getItem('accountInfo');
    if (savedData) {
      this.form = JSON.parse(savedData);
    }
  }
}
</script>

<style scoped>
.onboarding-container {
  background-color: #f9f9f9;
  border-radius: 12px;
  padding: 40px;
  box-shadow: 0 2px 12px 0 rgba(0, 0, 0, 0.1);
}

.header {
  text-align: center;
  margin-bottom: 40px;
}

.logo {
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: 20px;
}

.logo-img {
  width: 40px;
  height: 40px;
  margin-right: 10px;
}

.logo-text {
  font-size: 24px;
  font-weight: bold;
  color: #FF6B00;
}

.header h2 {
  margin: 0 0 10px 0;
  font-size: 28px;
  color: #333;
}

.header p {
  margin: 0;
  color: #666;
  font-size: 16px;
}

.form-section {
  background-color: white;
  border-radius: 8px;
  padding: 30px;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.05);
}

.form-section h3 {
  margin: 0 0 10px 0;
  font-size: 20px;
  color: #333;
}

.form-section h4 {
  margin: 30px 0 20px 0;
  font-size: 16px;
  color: #333;
  border-bottom: 1px solid #f0f0f0;
  padding-bottom: 10px;
}

.section-desc {
  margin: 0 0 30px 0;
  color: #666;
  font-size: 14px;
}

.upload-box {
  width: 100%;
}

.form-buttons {
  margin-top: 40px;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.action-buttons {
  display: flex;
  align-items: center;
}

.action-buttons .el-button {
  margin-left: 10px;
}

.form-buttons .el-button {
  margin-left: 10px;
  padding: 0 30px;
  height: 40px;
  border-radius: 4px;
}

.save-draft-btn {
  border: 1px solid #DCDFE6;
  background-color: #FFFFFF;
  color: #606266;
}

.back-btn {
  border: 1px solid #DCDFE6;
  background-color: #FFFFFF;
  color: #606266;
}

.next-btn {
  background-color: #FF6B00 !important;
  border: none;
  color: #FFFFFF;
}

.next-btn:hover {
  background-color: #FF8533 !important;
}

.footer-note {
  margin-top: 30px;
  text-align: center;
  font-size: 12px;
  color: #999;
}

/* 表单内容区域样式调整 */
:deep(.el-form-item__content) {
  width: 100%;
  justify-content: space-between;
  margin-left: 0px !important;
}
</style>